// components/Player.tsx
"use client";
import type { SongType } from "@/types/globalTypes";
import { Slider } from "./ui/slider";
import { useEffect, useState, useMemo, useCallback } from "react";
import { Volume1, Volume2, VolumeX } from "lucide-react";
import Link from "next/link";
import Image from "next/image";

// Import Controls and ProgressBar dynamically
const Controls = dynamic(() => import("./Controls"), { ssr: false });
const ProgressBar = dynamic(() => import("./ProgressBar"), { ssr: false });

// IMPORTANT: Import dynamic at the top
import dynamic from "next/dynamic";

const Player = () => {
    const [isClient, setIsClient] = useState(false);
    const [audio, setAudio] = useState<any>(null);
    const [volume, setVolume] = useState(100);
    const [prevVolume, setPrevVolume] = useState(100);

    // Load audio module only on client
    useEffect(() => {
        setIsClient(true);

        // Dynamically import the audio hook
        import("@splicemood/react-music-player").then((module) => {
            const { useAudio } = module;
            setAudio(() => useAudio<SongType>);
        });
    }, []);

    // Only initialize audio when it's loaded
    const audioInstance = audio ? audio() : null;

    useEffect(() => {
        if (
            audioInstance?.volume !== undefined &&
            !isNaN(audioInstance.volume)
        ) {
            const newVolume = Math.round(audioInstance.volume * 100);
            setVolume(newVolume);
            if (newVolume > 0) {
                setPrevVolume(newVolume);
            }
        }
    }, [audioInstance?.volume]);

    const currentSong = useMemo(() => {
        if (!audioInstance) return undefined;
        if (
            audioInstance.playlist?.length > 0 &&
            audioInstance.currentTrackIndex !== undefined
        ) {
            return audioInstance.playlist[audioInstance.currentTrackIndex];
        }
        return undefined;
    }, [audioInstance?.playlist, audioInstance?.currentTrackIndex]);

    const displayVolume = useMemo(
        () => (isNaN(volume) ? 0 : Math.min(100, Math.max(0, volume))),
        [volume],
    );

    const VolumeIcon = useMemo(() => {
        if (displayVolume === 0) return VolumeX;
        return displayVolume < 50 ? Volume1 : Volume2;
    }, [displayVolume]);

    const handleVolumeChange = useCallback(
        (value: number[]) => {
            if (!audioInstance) return;
            const newVolume = Math.round(value[0]);
            setVolume(newVolume);
            if (newVolume > 0) {
                setPrevVolume(newVolume);
            }
            audioInstance.setVolume(newVolume / 100);
        },
        [audioInstance],
    );

    const toggleMute = useCallback(() => {
        if (!audioInstance) return;
        if (volume === 0) {
            audioInstance.setVolume(prevVolume / 100);
            setVolume(prevVolume);
        } else {
            setPrevVolume(volume);
            audioInstance.setVolume(0);
            setVolume(0);
        }
    }, [audioInstance, volume, prevVolume]);

    const sliderClasses = useMemo(
        () => ({
            trackClassName:
                "h-1 bg-neutral-700 rounded-full transition-all duration-200",
            rangeClassName: "bg-[#a1a1a1] group-hover:bg-white rounded-full",
            thumbClassName:
                "block w-3 h-3 bg-white rounded-full shadow-lg opacity-0 group-hover:opacity-100 hover:scale-125 transition-all duration-200 focus:outline-none",
        }),
        [],
    );

    // Don't render anything on server
    if (!isClient || !audioInstance) {
        return (
            <div className="w-full fixed bottom-5 items-center flex h-16 bg-black/20 backdrop-blur-sm">
                <div className="flex items-center flex-1/4 ml-10 gap-3">
                    <div className="w-16 h-16 bg-gray-700 rounded-lg animate-pulse" />
                    <div>
                        <div className="h-5 w-32 bg-gray-700 rounded animate-pulse mb-2" />
                        <div className="h-4 w-24 bg-gray-700 rounded animate-pulse" />
                    </div>
                </div>
            </div>
        );
    }

    const SongInfo = (
        <div className="flex items-center flex-1/4 ml-10 gap-3">
            {currentSong ? (
                <>
                    <div className="w-16 h-16">
                        <Image
                            width={64}
                            height={64}
                            className="w-16 h-16 rounded-lg object-cover"
                            src={currentSong.cover}
                            alt={currentSong.title}
                        />
                    </div>
                    <div>
                        <h1 className="text-white">{currentSong.title}</h1>
                        <Link
                            href={currentSong.artistLink || "#"}
                            className="text-[#a1a1a1] hover:underline transition"
                        >
                            {currentSong.artist}
                        </Link>
                    </div>
                </>
            ) : (
                <div className="text-white">No track selected</div>
            )}
        </div>
    );

    const VolumeControl = (
        <div className="w-48 flex items-center gap-2">
            <button
                onClick={toggleMute}
                className="focus:outline-none cursor-pointer text-[#a1a1a1] hover:text-white"
                aria-label={displayVolume === 0 ? "Unmute" : "Mute"}
            >
                <VolumeIcon className="w-6 h-6" />
            </button>

            <Slider
                value={[displayVolume]}
                min={0}
                max={100}
                step={1}
                onValueChange={handleVolumeChange}
                className="w-full group"
                trackClassName={sliderClasses.trackClassName}
                rangeClassName={sliderClasses.rangeClassName}
                thumbClassName={sliderClasses.thumbClassName}
                showThumb={true}
            />

            <span className="text-[#a1a1a1] select-none text-md min-w-10">
                {displayVolume}%
            </span>
        </div>
    );

    return (
        <div className="w-full fixed bottom-5 items-center flex h-16 bg-black/20 backdrop-blur-sm">
            {SongInfo}

            <div className="flex flex-col flex-3/4 gap-2 items-center justify-center">
                <Controls />
                <ProgressBar />
            </div>

            <div className="flex-1/4 flex justify-end mr-10">
                {VolumeControl}
            </div>
        </div>
    );
};

export default Player;
